import{_ as a,c as n,o as s,a as t}from"./app.1e429f93.js";const g='{"title":"Guide","description":"","frontmatter":{},"headers":[{"level":2,"title":"Basics","slug":"basics"},{"level":2,"title":"Checking for validation state","slug":"checking-for-validation-state"},{"level":2,"title":"The dirty state","slug":"the-dirty-state"},{"level":3,"title":"Using $touch","slug":"using-touch"},{"level":3,"title":"Using the $model property","slug":"using-the-model-property"},{"level":3,"title":"Setting dirty state with $autoDirty","slug":"setting-dirty-state-with-autodirty"},{"level":3,"title":"Lazy validations","slug":"lazy-validations"},{"level":3,"title":"Resetting dirty state","slug":"resetting-dirty-state"},{"level":2,"title":"Collective properties","slug":"collective-properties"},{"level":2,"title":"Displaying error messages","slug":"displaying-error-messages"},{"level":2,"title":"Validating forms before submitting","slug":"validating-forms-before-submitting"}],"relativePath":"guide.md","lastUpdated":1777558301324}',e={},o=t(`<h1 id="guide" tabindex="-1">Guide <a class="header-anchor" href="#guide" aria-hidden="true">#</a></h1><h2 id="basics" tabindex="-1">Basics <a class="header-anchor" href="#basics" aria-hidden="true">#</a></h2><p>As we mentioned in the <a href="/#getting-started-2">getting started guide</a>, validation rules are defined inside the object returned by the <code>validations</code> method. We will refer to those as just <em>validations</em> from now on.</p><p>You can access the component&#39;s instance, and its properties via <code>this</code> when writing more complicated validation rules.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>Note:</strong> Pre Vuelidate 2 <code>validations</code> was allowed to be an object as well as a function. This is still available, for backwards compatibility reasons, but is discouraged. Please migrate to a method instead.</p></div><p>Each validation rule must have a corresponding property inside the <code>data</code> object.</p><div class="language-html"><pre><code>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">setup</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">v$</span><span class="token operator">:</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>Vuelidate comes with a set of validators, that live inside the <code>@vuelidate/validations</code> package, which you must install separately. For a full list of available validators, check the <a href="./validators.html">Validators</a> page.</p><p>Validators are functions that receive the matching value and return either a <code>boolean</code> or an object with a <code>$valid</code> property. If the validation passes, return <code>true</code> or <code>{ $valid: true }</code>, <code>false</code> otherwise.</p><p>The built-in validators are additionally wrapped in an object which contains several additional properties like:</p><ul><li><code>$validator</code> \u2013 contains the validation function</li><li><code>$message</code> \u2013 contains the validator\u2019s error message</li><li><code>$params</code> \u2013 contains the params that are passed during validator configuration (applies to validators that accept configuration)</li></ul><p>Here\u2019s an example of how the <code>minLength</code> validator looks like:</p><div class="language-js"><pre><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">minLength</span> <span class="token punctuation">(</span><span class="token parameter">min</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">$validator</span><span class="token operator">:</span> <span class="token function">minLength</span><span class="token punctuation">(</span>min<span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token function-variable function">$message</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token parameter"><span class="token punctuation">{</span> $params <span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">This field should be at least </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>$params<span class="token punctuation">.</span>min<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string"> long.</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span>
    <span class="token literal-property property">$params</span><span class="token operator">:</span> <span class="token punctuation">{</span> min <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>Vuelidate also supports writing your own custom validators, you can learn more about how to write your own validators on the <a href="./custom_validators.html">Custom Validators</a> page.</p><h2 id="checking-for-validation-state" tabindex="-1">Checking for validation state <a class="header-anchor" href="#checking-for-validation-state" aria-hidden="true">#</a></h2><p>Now that we have our validation rules set up, we can start checking for errors.</p><p>Vuelidate builds a validation state, that can be accessed via the exposed Vuelidate property (this is the property name that you return from <code>setup</code>), most commonly called <code>v$</code> or just <code>v</code>. It is a nested object that follows your <code>validations</code> structure, but with some extra validity related properties.</p><p><code>v$</code> is also reactive - meaning it changes as the user interacts with the state!</p><p>Building up on our form example above, to check whether name is valid we can now check to see if the <code>name.$error</code> property is <code>true</code> or <code>false</code>, and display an error for our users.</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>label</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>name<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">v-if</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>v$.name.$error<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Name field has an error.<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>label</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>Using this approach, you can apply error classes, show messages or add attributes.</p><p>The properties you will check against most often are:</p><div class="language-"><pre><code>  &quot;$dirty&quot;: false,
  &quot;$error&quot;: false,
  &quot;$errors&quot;: [],
  &quot;$silentErrors&quot;: [],
  &quot;$invalid&quot;: false,
</code></pre></div><p>This is just a subset of all the properties, but they are enough to get us started. To see all available properties, check the <a href="./api/state.html">Validation state API</a></p><h2 id="the-dirty-state" tabindex="-1">The dirty state <a class="header-anchor" href="#the-dirty-state" aria-hidden="true">#</a></h2><p>Vuelidate tracks the <code>$dirty</code> state of each property. This is used to keep fields from showing as invalid, before the user has interacted with them.</p><p>A property is considered <code>$dirty</code> after it has received some sort of interaction from the user, which means all properties begin with a <code>$dirty</code> state of <code>false</code>.</p><p>There are two properties, attached to each validation field, that are used to check if said field is valid, <code>$invalid</code> and <code>$error</code>.</p><p>Although the validations will run in the background updating the <code>$invalid</code> state, the <code>$error</code> will stay <code>false</code> until both the <code>$dirty</code> and <code>$invalid</code> states are <code>true</code>.</p><p>There are multiple ways to update the <code>$dirty</code> state.</p><h3 id="using-touch" tabindex="-1">Using <code>$touch</code> <a class="header-anchor" href="#using-touch" aria-hidden="true">#</a></h3><p>You can programmatically update the <code>$dirty</code> state by calling the <code>$touch</code> method on a validation field. For example, for the <code>name</code> field you can call <code>v$.name.$touch()</code> to change it\u2019s <code>$dirty</code> state.</p><p>Here\u2019s an example of adding it to the above form, where we attach it to the <code>@blur</code> event so that our error only shows up after the user entered and left the input.</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>label</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>name<span class="token punctuation">&quot;</span></span> <span class="token attr-name">@blur</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>v$.name.$touch<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">v-if</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>v$.name.$error<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Name field has an error.<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>label</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>If you want to change the <code>$dirty</code> state for more than one property, you can also use <code>v$.$touch()</code>, which will call <code>$touch</code> on all the nested properties. <code>$touch</code> is attached to each field, to its parent, all the way up to the root of the validation.</p><p>This is useful in cases where you have a <strong>Submit</strong> button and want to trigger the whole form <code>$dirty</code>. See <a href="./guide.html#validating-forms-before-submitting">Validating Forms Before Submitting</a> for an example.</p><h3 id="using-the-model-property" tabindex="-1">Using the <code>$model</code> property <a class="header-anchor" href="#using-the-model-property" aria-hidden="true">#</a></h3><p>Another way to ensure that the <code>$dirty</code> state is updated when a user interacts with an input, is to directly bind your input&#39;s <code>v-model</code> declaration to the <code>$model</code> of that field&#39;s validation object.</p><p>This is a special property that acts as a &quot;proxy&quot; to the targeted property. When you modify it, it calls <code>$touch()</code> for that property and then proceeds to update the original value.</p><div class="language-html"><pre><code>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>v$.name.$model<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>

<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function-variable function">setup</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">v$</span><span class="token operator">:</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>This binding is accomplished internally through a getter/setter that reads and updates the original state. When the setter is called, it also triggers <code>$touch()</code> for that property.</p><h3 id="setting-dirty-state-with-autodirty" tabindex="-1">Setting dirty state with <code>$autoDirty</code> <a class="header-anchor" href="#setting-dirty-state-with-autodirty" aria-hidden="true">#</a></h3><p>It is quite common to forget to use <code>$model</code> or <code>$touch</code>. If you want to ensure dirty state is always tracked, you can use the <code>$autoDirty</code> config param, when defining your validation rules.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function-variable function">setup</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">v$</span><span class="token operator">:</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> <span class="token literal-property property">$autoDirty</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>This will create an internal watcher, that will update <code>$dirty</code>, the moment that field property is changed. It will ensure the validator tracks its bound data, and sets the dirty state accordingly.</p><p>You can then change your field&#39;s <code>v-model</code> expression to just the data property:</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>name<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
</code></pre></div><div class="tip custom-block"><p class="custom-block-title">You can pass \`$autoDirty\` to all validators, by defining it in the global config</p><ul><li><a href="./advanced_usage.html#providing-global-config-to-your-vuelidate-instance">Providing global config to your Vuelidate instance</a></li></ul></div><h3 id="lazy-validations" tabindex="-1">Lazy validations <a class="header-anchor" href="#lazy-validations" aria-hidden="true">#</a></h3><p>Validation in Vuelidate 2 introduces the <code>$lazy</code> param, which will make the selected validators lazy. That means they will only be called, after the field is <code>$dirty</code>, so after <code>touch()</code> is called, by using that property\u2019s <code>$model</code> or by also using the <code>$autoDirty</code> param.</p><p>This saves extra invocations for async validators as well as makes the initial validation setup a bit more performant.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function-variable function">setup</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">v$</span><span class="token operator">:</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> <span class="token literal-property property">$lazy</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><div class="tip custom-block"><p class="custom-block-title">You can pass \`$lazy\` to all validators, by defining it in the global config</p><ul><li><a href="./advanced_usage.html#providing-global-config-to-your-vuelidate-instance">Providing global config to your Vuelidate instance</a></li></ul></div><h3 id="resetting-dirty-state" tabindex="-1">Resetting dirty state <a class="header-anchor" href="#resetting-dirty-state" aria-hidden="true">#</a></h3><p>If you wish to reset a form&#39;s <code>$dirty</code> state, you can do so by using the appropriately named <code>$reset</code> method. For example when closing a create/edit modal, you don&#39;t want the validation state to persist.</p><div class="language-html"><pre><code>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>app-modal</span> <span class="token attr-name">@closed</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>v$.$reset()<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token comment">&lt;!-- some inputs  --&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>app-modal</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><h2 id="collective-properties" tabindex="-1">Collective properties <a class="header-anchor" href="#collective-properties" aria-hidden="true">#</a></h2><p>The validation state has entries for each validator, that hold a set of helpful properties that we can use to show warnings, add classes and more.</p><div class="language-json"><pre><code><span class="token punctuation">{</span>
  <span class="token property">&quot;$dirty&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
  <span class="token property">&quot;$error&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
  <span class="token property">&quot;$errors&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token property">&quot;$silentErrors&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token property">&quot;$invalid&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
  <span class="token comment">// ...other properties</span>
  <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;$dirty&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
    <span class="token property">&quot;required&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
      <span class="token property">&quot;$message&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Value is required&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;$params&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
      <span class="token property">&quot;$pending&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
      <span class="token property">&quot;$invalid&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token property">&quot;$invalid&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
    <span class="token property">&quot;$pending&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
    <span class="token property">&quot;$error&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
    <span class="token property">&quot;$errors&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token property">&quot;$silentErrors&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
    <span class="token comment">// ...other properties</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>As you can see, the <code>name</code> field has its own <code>$dirty</code>, <code>$error</code> among other attributes, as well as an object for the <code>required</code> validator.</p><p>The root properties like, <code>$dirty</code>, <code>$error</code> and <code>$invalid</code> are all collective computed properties, meaning their value changes depending on the nested children&#39;s state.</p><p><strong>Example:</strong> If a form has 10 fields and one of them has its <code>$error: true</code>, then the root <code>$error</code> will also be <code>true</code>, giving additional flexibility when trying to display error state.</p><h2 id="displaying-error-messages" tabindex="-1">Displaying error messages <a class="header-anchor" href="#displaying-error-messages" aria-hidden="true">#</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>All validators in Vuelidate 2 include error messages.</p></div><p>The validation state holds useful data, like the invalid state of each property validator, along with extra properties, like an error message or extra parameters.</p><p>Error messages come out of the box with the bundled validators in <code>@vuelidate/validators</code> package. You can see how to customise error messages at the <a href="./custom_validators.html">Custom Validators page</a></p><p>The easiest way to display errors is to use the form&#39;s top level <code>$errors</code> property. It is an array of validation objects, that you can iterate over. Use the <code>$uid</code> property for your <code>key</code>.</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span>
  <span class="token attr-name">v-for</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error of v$.$errors<span class="token punctuation">&quot;</span></span>
  <span class="token attr-name">:key</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error.$uid<span class="token punctuation">&quot;</span></span>
<span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>strong</span><span class="token punctuation">&gt;</span></span>{{ error.$validator }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>strong</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>small</span><span class="token punctuation">&gt;</span></span> on property<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>small</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>strong</span><span class="token punctuation">&gt;</span></span>{{ error.$property }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>strong</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>small</span><span class="token punctuation">&gt;</span></span> says:<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>small</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>strong</span><span class="token punctuation">&gt;</span></span>{{ error.$message }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>strong</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>You can also check for errors on each form property:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span>
  <span class="token attr-name">v-for</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error of v$.name.$errors<span class="token punctuation">&quot;</span></span>
  <span class="token attr-name">:key</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error.$uid<span class="token punctuation">&quot;</span></span>
<span class="token punctuation">&gt;</span></span>
<span class="token comment">&lt;!-- Same as above --&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><h2 id="validating-forms-before-submitting" tabindex="-1">Validating forms before submitting <a class="header-anchor" href="#validating-forms-before-submitting" aria-hidden="true">#</a></h2><p>To submit a form, you often need to validate it first. It is a good practice to call the <code>$validate</code> method on the form first, so all validators (including those with <code>$lazy: true</code>) are run. This will also cause all the errors to show up that were hidden due to <code>$dirty</code> state being <code>false</code>.</p><p>It returns a promise, which resolves with a boolean when all validators resolve, depending on the validation status.</p><div class="language-js"><pre><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">methods</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token keyword">async</span> <span class="token function">submitForm</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">const</span> isFormCorrect <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>v$<span class="token punctuation">.</span><span class="token function">$validate</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
      <span class="token comment">// you can show some extra alert to the user or just leave the each field to show it&#39;s \`$errors\`.</span>
      <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>isFormCorrect<span class="token punctuation">)</span> <span class="token keyword">return</span>
      <span class="token comment">// actually submit form</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div>`,74),p=[o];function c(l,i,r,u,d,k){return s(),n("div",null,p)}var m=a(e,[["render",c]]);export{g as __pageData,m as default};
